INSERT INTO public.hypotheses (hypothesis_number, domain, hypothesis, metric, test_method, success_criteria) VALUES
(1, 'مزوّدي الخدمات', 'نعتقد أن المزودين يرون المنصة قناة بيع مجدية لذلك سيستمرون بالنشاط وتقديم العروض بشكل منتظم', 'نسبة المزودين النشطين شهريًا + عروض/أسبوع + صفقات', 'تتبع النشاط أسبوعيًا + Cohort', '≥40% من المزودين نشطين + ≥60% بقاء لنهاية الشهر الثالث'),
(2, 'مزوّدي الخدمات', 'نعتقد أن سرعة استجابة المزود لأول عرض ترفع معدل الإغلاق', 'زمن طلب→أول عرض + معدل الإغلاق', 'ربط الزمن بنتيجة الطلب', '80% يصل لأول عرض خلال 48 ساعة + تحسن الإغلاق مع انخفاض الزمن'),
(3, 'مزوّدي الخدمات', 'نعتقد أن زيادة عدد المزودين النشطين تخفض زمن الوصول لأول عرض وترفع الإغلاق', 'زمن أول عرض + الإغلاق قبل/بعد نمو المزودين', 'مقارنة شهرية مرتبطة بعدد المزودين', 'كل +10 مزودين نشطين: زمن أول عرض ↓ والإغلاق ↑ بوضوح'),
(4, 'مزوّدي الخدمات', 'نعتقد أن المزودين عندما يكيّفون عروضهم للجمعيات من حيث السعر والنطاق وآلية التسليم يزيد الإغلاق', 'نسبة عروض مخصصة + خصومات + تعديلات نطاق', 'تحليل العروض والتفاوض', '≥30% من العروض "مكيّفة"'),
(5, 'مزوّدي الخدمات', 'نعتقد أن وجود عروض خاصة للمنصة يرفع التحويل ويزيد الثقة', 'نسبة مزودين لديهم باقات "خاص للمنصة" + التحويل', 'تحليل الكتالوج + مقارنة التحويل', '≥25% من المزودين لديهم باقات خاصة خلال 60 يوم + تحسن التحويل'),
(6, 'مزوّدي الخدمات', 'نعتقد أن تصنيف المزودين إلى طبقات جودة يرفع الإغلاق أكثر من مجرد زيادة العدد', 'الإغلاق حسب الطبقة + وقت القرار', 'تطبيق Tiering تجريبي ومقارنة', 'طبقة "معتمد" تحقق إغلاق أعلى ≥20%'),
(7, 'مزوّدي الخدمات', 'نعتقد أن جودة التنفيذ لدى المزودين ستكون مستقرة وعلى مستوى السوق أو أفضل', 'تقييمات 4/5+ + تدقيق جودة + شكاوى جوهرية', 'تدقيق عيّني شهري + مراجعة الشكاوى', '≥70% تقييم 4/5+ + شكاوى جوهرية ≤10%'),
(8, 'مزوّدي الخدمات', 'نعتقد أن النزاعات ستكون منخفضة ويمكن إدارتها ضمن زمن حل محدد', 'نسبة عمليات بلا نزاع + زمن حل النزاع', 'سجل النزاعات + تتبع زمن الحل', '≥90% بلا نزاع جوهري + 80% تُحل خلال ≤7 أيام'),
(9, 'مزوّدي الخدمات', 'نعتقد أن التزام المزودين بالمواعيد وفق SLA يرفع رضا الجمعيات ويزيد إعادة الشراء', 'نسبة الالتزام + الرضا + إعادة الشراء', 'مقارنة ملتزم/غير ملتزم', '≥80% تسليم في الوقت + رضا أعلى بوضوح'),
(10, 'مزوّدي الخدمات', 'نعتقد أن حوافز الاستجابة السريعة للمزود سترفع الإغلاق', 'معدل الاستجابة + الإغلاق قبل/بعد الحافز', 'تجربة A/B أو قبل/بعد', 'تحسن الإغلاق ≥10% مع انخفاض زمن الاستجابة'),
(11, 'الجمعيات', 'نعتقد أن احتياج الجمعيات متكرر ومؤلم لذلك سيخلق طلبًا مستمرًا على الخدمات', 'تكرار الطلب/90 يوم + أسباب الطلب', 'تحليل السجل وتصنيف الأسباب', '≥1 طلب/90 يوم لكل جمعية نشطة + ≥60% أسباب تشغيلية/امتثال'),
(12, 'الجمعيات', 'نعتقد أن العائق الأساسي ليس التسجيل بل الوصول لأول طلب فعلي', 'تحويل تسجيل→أول طلب + زمن التحول', 'تتبع Funnel', '≥50% يتحولون لأول طلب خلال 14 يوم'),
(13, 'الجمعيات', 'نعتقد أن تبسيط نموذج الطلب وتوفير قوالب المتطلبات يقلل التعثر ويرفع التحويل', 'نسبة تعثر بسبب المتطلبات + زمن إنشاء الطلب', 'تجربة A/B لتبسيط النموذج', 'خفض التعثر ≥30% + زيادة التحويل ≥15%'),
(14, 'الجمعيات', 'نعتقد أن نوع الخدمة صغيرة مقابل حزم يغيّر معدل الإغلاق ومتوسط السلة', 'الإغلاق + متوسط السلة حسب النوع', 'تصنيف الطلبات ومقارنة', 'نمط واحد يتفوق ≥30% ويُعتمد كمسار افتراضي'),
(15, 'الجمعيات', 'نعتقد أن شفافية التسعير تقلل رفض العروض وتسرّع اتخاذ القرار', 'نسبة رفض بسبب السعر + زمن قرار الشراء', 'إضافة نطاق سعري/مرجع سوق ومقارنة', 'خفض رفض السعر ≥20% + تقليل زمن القرار ≥15%'),
(16, 'الجمعيات', 'نعتقد أن توفير حزمة بداية للجمعية يرفع التحول لأول طلب', 'تحويل التسجيل→أول طلب خلال 14 يوم', 'إطلاق Quick Start ومقارنة', 'زيادة التحول ≥20% خلال شهر'),
(17, 'الجمعيات', 'نعتقد أن الدعم أثناء التنفيذ وبعد الخدمة يرفع الرضا ويزيد إعادة الشراء', 'رضا + إعادة شراء + شكاوى دعم', 'CSAT/NPS + تتبع التكرار', 'إعادة شراء 20% خلال 120 يوم + انخفاض الشكاوى'),
(18, 'نموذج العمل', 'نعتقد أن الدفع الذاتي موجود وقابل للنمو ضمن شريحة معتبرة من الجمعيات', 'نسبة عمليات دفع ذاتي + متوسط قيمة العملية', 'وسم مصدر الدفع + تحليل شهري', '≥25% دفع ذاتي خلال 90 يوم مع نمو شهري'),
(19, 'نموذج العمل', 'نعتقد أن نموذج الرسوم أو العمولة إذا صُمم بشكل مناسب لن يطرد المزود ولن يضعف تنافسية السعر', 'نشاط المزود + تنافسية السعر + رضا المزود', 'اختبار هيكل رسوم تجريبي + استطلاع', 'ثبات/تحسن نشاط المزود + ≥70% الأسعار ضمن السوق'),
(20, 'نموذج العمل', 'نعتقد أن تحسين التسعير عبر نطاقات وباقات ومقارنة سوق يزيد الدفع الذاتي ويثبت الإغلاق', 'الدفع الذاتي + الإغلاق + رفض السعر', 'تطبيق تسعير/مرجع سوق ومتابعة', 'زيادة الدفع الذاتي ≥10% وخفض رفض السعر ≥20%'),
(21, 'نموذج العمل', 'نعتقد أن ربحية وحدة التشغيل ممكنة عند حجم معاملات محدد دون تضخم تشغيلي', 'تكلفة تشغيل/طلب + هامش مساهمة', 'حساب Unit Economics', 'نقطة تعادل واضحة عند حجم معاملات محدد خلال 6–12 شهر'),
(22, 'التشغيل والحوكمة', 'نعتقد أن عنق الزجاجة الأساسي تشغيلي أكثر من كونه تقنيًا', 'توزيع أسباب التعثر (تشغيلي/سعري/ثقة/تقني)', 'وسم سبب التعثر لكل طلب', 'إذا الغالب "تشغيلي" نركز إجراءات وتشغيل قبل تطوير تقني'),
(23, 'التشغيل والحوكمة', 'نعتقد أن تطبيق آلية واضحة لفض النزاعات يرفع الثقة ويقلل انسحاب الأطراف', 'نسبة انسحاب + زمن حل النزاع + رضا الطرفين', 'تطبيق SOP للنزاعات + قبل/بعد', 'خفض الانسحاب ≥15% + حل النزاع ≤7 أيام في 80%'),
(24, 'التشغيل والحوكمة', 'نعتقد أن الضمانات الخفيفة مثل الدفعات المرحلية أو الحجز تقلل المخاطر وترفع الإغلاق', 'الإغلاق + النزاعات + رضا الطرفين', 'تجربة دفعات مرحلية/حجز', 'تحسن الإغلاق ≥10% + انخفاض النزاعات ≥20%'),
(25, 'التشغيل والحوكمة', 'نعتقد أن جودة البيانات وتكاملها تمكّن من اتخاذ قرارات توسع وتحسين شهرية مبنية على أدلة', 'اكتمال البيانات + تقارير + قرارات مبنية على بيانات', 'تدقيق جودة البيانات + تتبع القرارات', 'تقرير شهري مكتمل + قرار واحد على الأقل مبني على بيانات'),
(26, 'التشغيل والحوكمة', 'نعتقد أن توحيد قوالب نطاق الخدمة يقلل إعادة العمل ويزيد سرعة الإغلاق', 'عدد مرات إعادة التوضيح + زمن الاتفاق', 'تطبيق Scope templates ومقارنة', 'خفض إعادة التوضيح ≥25% + تقليل زمن الاتفاق ≥15%');
